import React from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/01.png";
import img2 from "./images/02.png";
import img3 from "./images/03.png";
import "./App.css"; // Import the CSS file with styles for the marquee


function MarqueeExample() {
  return (
    <div className="marquee-container">
      <Marquee gradient={false} speed={40} direction="right">
        <div className="marquee-item">
          <div className="marquee-item-box">
          <img src={img1} alt="example" />
            <span>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</span>
          </div>
        </div>
        <div className="marquee-item">
          <div className="marquee-item-box">
          <img src={img2} alt="example" />
            <span>Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.</span>
          </div>
        </div>
        <div className="marquee-item">
          <div className="marquee-item-box">
          <img src={img3} alt="example" />
            <span>Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat.</span>
          </div>
        </div>
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
